26	import org.apache.camel.AsyncCallback;
27	import org.apache.camel.CamelContext;
28	import org.apache.camel.CamelExchangeException;
29	import org.apache.camel.Exchange;
30	import org.apache.camel.Expression;
31	import org.apache.camel.Navigate;
32	import org.apache.camel.Processor;
33	import org.apache.camel.Traceable;
34	import org.apache.camel.processor.resequencer.ResequencerEngine;
35	import org.apache.camel.processor.resequencer.SequenceElementComparator;
36	import org.apache.camel.processor.resequencer.SequenceSender;
37	import org.apache.camel.spi.ExceptionHandler;
38	import org.apache.camel.spi.IdAware;
39	import org.apache.camel.spi.RouteIdAware;
40	import org.apache.camel.spi.StepIdAware;
41	import org.apache.camel.support.ExchangeHelper;
42	import org.apache.camel.support.LoggingExceptionHandler;
43	import org.apache.camel.support.service.ServiceHelper;
44	import org.apache.camel.util.ObjectHelper;
45	import org.slf4j.Logger;
46	import org.slf4j.LoggerFactory;
47	
48	/**
49	 * A resequencer that re-orders a (continuous) stream of {@link Exchange}s. The algorithm implemented by
50	 * {@link ResequencerEngine} is based on the detection of gaps in a message stream rather than on a fixed batch size.
51	 * Gap detection in combination with timeouts removes the constraint of having to know the number of messages of a
52	 * sequence (i.e. the batch size) in advance.
53	 * <p>
54	 * Messages must contain a unique sequence number for which a predecessor and a successor is known. For example a
55	 * message with the sequence number 3 has a predecessor message with the sequence number 2 and a successor message with
56	 * the sequence number 4. The message sequence 2,3,5 has a gap because the successor of 3 is missing. The resequencer
57	 * therefore has to retain message 5 until message 4 arrives (or a timeout occurs).
58	 * <p>
59	 * Instances of this class poll for {@link Exchange}s from a given <code>endpoint</code>. Resequencing work and the
60	 * delivery of messages to the next <code>processor</code> is done within the single polling thread.
61	 *
62	 * @see ResequencerEngine
63	 */
64	public class StreamResequencer extends BaseProcessorSupport
65	        implements SequenceSender<Exchange>, Navigate<Processor>, Traceable, IdAware, RouteIdAware, StepIdAware {
66	
67	    private static final Logger LOG = LoggerFactory.getLogger(StreamResequencer.class);
68	
69	    private String id;
70	    private String routeId;
71	    private String stepId;
72	    private final CamelContext camelContext;
73	    private final ExceptionHandler exceptionHandler;
74	    private final ResequencerEngine<Exchange> engine;
75	    private final Processor processor;
76	    private final Expression expression;
77	    private Delivery delivery;
78	    private int capacity;
79	    private boolean ignoreInvalidExchanges;
80	    private long deliveryAttemptInterval = 1000L;
81	
82	    /**
83	     * Creates a new {@link StreamResequencer} instance.
84	     *
85	     * @param processor  next processor that processes re-ordered exchanges.
86	     * @param comparator a sequence element comparator for exchanges.
87	     */
88	    public StreamResequencer(CamelContext camelContext, Processor processor, SequenceElementComparator<Exchange> comparator,
89	                             Expression expression) {
90	        ObjectHelper.notNull(camelContext, "CamelContext");
91	        this.camelContext = camelContext;
92	        this.engine = new ResequencerEngine<>(comparator);
93	        this.engine.setSequenceSender(this);
94	        this.processor = processor;
95	        this.expression = expression;
96	        this.exceptionHandler = new LoggingExceptionHandler(camelContext, getClass());
97	    }
98	
99	    public Expression getExpression() {
100	        return expression;
101	    }
102	
103	    /**
104	     * Returns this resequencer's exception handler.
105	     */
106	    public ExceptionHandler getExceptionHandler() {
107	        return exceptionHandler;
108	    }
109	
110	    /**
111	     * Returns the next processor.
112	     */
113	    public Processor getProcessor() {
114	        return processor;
115	    }
116	
117	    /**
118	     * Returns this resequencer's capacity. The capacity is the maximum number of exchanges that can be managed by this
119	     * resequencer at a given point in time. If the capacity if reached, polling from the endpoint will be skipped for
120	     * <code>timeout</code> milliseconds giving exchanges the possibility to time out and to be delivered after the
121	     * waiting period.
122	     *
123	     * @return this resequencer's capacity.
124	     */
125	    public int getCapacity() {
126	        return capacity;
127	    }
128	
129	    /**
130	     * Returns this resequencer's timeout. This sets the resequencer engine's timeout via
131	     * {@link ResequencerEngine#setTimeout(long)}. This value is also used to define the polling timeout from the
132	     * endpoint.
133	     *
134	     * @return this resequencer's timeout. (Processor)
135	     * @see    ResequencerEngine#setTimeout(long)
136	     */
137	    public long getTimeout() {
138	        return engine.getTimeout();
139	    }
140	
141	    public void setCapacity(int capacity) {
142	        this.capacity = capacity;
143	    }
144	
145	    public void setTimeout(long timeout) {
146	        engine.setTimeout(timeout);
147	    }
148	
149	    public void setDeliveryAttemptInterval(long deliveryAttemptInterval) {
150	        this.deliveryAttemptInterval = deliveryAttemptInterval;
151	    }
152	
153	    public boolean isIgnoreInvalidExchanges() {
154	        return ignoreInvalidExchanges;
155	    }
156	
157	    public void setRejectOld(Boolean rejectOld) {
158	        engine.setRejectOld(rejectOld);
159	    }
160	
161	    public boolean isRejectOld() {
162	        return engine.getRejectOld() != null && engine.getRejectOld();
163	    }
164	
165	    /**
166	     * Sets whether to ignore invalid exchanges which cannot be used by this stream resequencer.
167	     * <p/>
168	     * Default is <tt>false</tt>, by which an {@link CamelExchangeException} is thrown if the {@link Exchange} is
169	     * invalid.
170	     */
171	    public void setIgnoreInvalidExchanges(boolean ignoreInvalidExchanges) {
172	        this.ignoreInvalidExchanges = ignoreInvalidExchanges;
173	    }
174	
175	    @Override
176	    public String toString() {
177	        return id;
178	    }
179	
180	    @Override
181	    public String getTraceLabel() {
182	        return "streamResequence";
183	    }
184	
185	    @Override
186	    public String getId() {
187	        return id;
188	    }
189	
190	    @Override
191	    public void setId(String id) {
192	        this.id = id;
193	    }
194	
195	    @Override
196	    public String getRouteId() {
197	        return routeId;
198	    }
199	
200	    @Override
201	    public void setRouteId(String routeId) {
202	        this.routeId = routeId;
203	    }
204	
205	    @Override
206	    public String getStepId() {
207	        return stepId;
208	    }
209	
210	    @Override
211	    public void setStepId(String stepId) {
212	        this.stepId = stepId;
213	    }
214	
215	    @Override
216	    protected void doBuild() throws Exception {
217	        ServiceHelper.buildService(processor);
218	    }
219	
220	    @Override
221	    protected void doInit() throws Exception {
222	        ServiceHelper.initService(processor);
223	    }
224	
225	    @Override
226	    protected void doStart() throws Exception {
227	        ServiceHelper.startService(processor);
228	        delivery = new Delivery();
229	        engine.start();
230	        delivery.start();
231	    }
232	
233	    @Override
234	    protected void doStop() throws Exception {
235	        // let's stop everything in the reverse order
236	        // no need to stop the worker thread -- it will stop automatically when this service is stopped
237	        engine.stop();
238	        ServiceHelper.stopService(processor);
239	    }
240	
241	    /**
242	     * Sends the <code>exchange</code> to the next <code>processor</code>.
243	     *
244	     * @param exchange exchange to send.
245	     */
246	    @Override
247	    public void sendElement(Exchange exchange) throws Exception {
248	        processor.process(exchange);
249	    }
250	
251	    @Override
252	    public boolean process(Exchange exchange, AsyncCallback callback) {
253	        try {
254	            engine.waitUntil(s -> s.size() < capacity);
255	        } catch (InterruptedException e) {
256	            Thread.currentThread().interrupt();
257	            // we were interrupted so break out
258	            exchange.setException(e);
259	            callback.done(true);
260	            return true;
261	        }
262	
263	        try {
264	            // need to make defensive copy that are put on the sequencer queue
265	            Exchange copy = ExchangeHelper.createCorrelatedCopy(exchange, true);
266	            engine.insert(copy);
267	            delivery.request();
268	        } catch (Exception e) {
269	            if (isIgnoreInvalidExchanges()) {
270	                LOG.debug("Invalid Exchange. This Exchange will be ignored: {}", exchange);
271	            } else {
272	                exchange.setException(
273	                        new CamelExchangeException("Error processing Exchange in StreamResequencer", exchange, e));
274	            }
275	        }
276	
277	        callback.done(true);
278	        return true;
279	    }
280	
281	    @Override
282	    public boolean hasNext() {
283	        return processor != null;
284	    }
285	
286	    @Override
287	    public List<Processor> next() {
288	        if (!hasNext()) {
289	            return null;
290	        }
291	        List<Processor> answer = new ArrayList<>(1);
292	        answer.add(processor);
293	        return answer;
294	    }
295	
296	    class Delivery extends Thread {
297	
298	        private final Lock deliveryRequestLock = new ReentrantLock();
299	        private final Condition deliveryRequestCondition = deliveryRequestLock.newCondition();
300	
301	        Delivery() {
302	            super(camelContext.getExecutorServiceManager().resolveThreadName("Resequencer Delivery"));
303	        }
304	
305	        @Override
306	        public void run() {
307	            while (isRunAllowed()) {
308	                try {
309	                    deliveryRequestLock.lock();
310	                    try {
311	                        deliveryRequestCondition.await(deliveryAttemptInterval, TimeUnit.MILLISECONDS);
312	                    } finally {
313	                        deliveryRequestLock.unlock();
314	                    }
315	                } catch (InterruptedException e) {
316	                    Thread.currentThread().interrupt();
317	                    break;
318	                }
319	                try {
320	                    engine.deliver();
321	                } catch (Exception t) {
322	                    // a fail-safe to handle all exceptions being thrown
323	                    getExceptionHandler().handleException(t);
324	                }
325	            }
326	        }
327	
328	        public void cancel() {
329	            interrupt();
330	        }
331	
332	        public void request() {
333	            deliveryRequestLock.lock();
334	            try {
335	                deliveryRequestCondition.signal();
336	            } finally {
337	                deliveryRequestLock.unlock();
338	            }
339	        }
340	
341	    }
342	
343	}
