166	     * Sets whether to ignore invalid exchanges which cannot be used by this stream resequencer.
167	     * <p/>
168	     * Default is <tt>false</tt>, by which an {@link CamelExchangeException} is thrown if the {@link Exchange} is
169	     * invalid.
170	     */
171	    public void setIgnoreInvalidExchanges(boolean ignoreInvalidExchanges) {
172	        this.ignoreInvalidExchanges = ignoreInvalidExchanges;
173	    }
