package org.apache.camel.processor.resequencer;

/**
 * A {@link SequenceElementComparator} that reverses the delivery order of a delegate comparator.
 * <p/>
 * Simply negating {@link #compare(Object, Object)} is not sufficient for a {@link ResequencerEngine} because the
 * engine also relies on {@link #predecessor(Object, Object)} and {@link #successor(Object, Object)} to detect
 * contiguous elements and to cancel or schedule delivery timeouts. Reversing the delivery order therefore also
 * requires swapping the predecessor/successor relations, so that an element which is the delegate's successor
 * becomes this comparator's predecessor, and vice versa.
 */
public class ReverseSequenceElementComparator<E> implements SequenceElementComparator<E> {

    private final SequenceElementComparator<E> delegate;

    public ReverseSequenceElementComparator(SequenceElementComparator<E> delegate) {
        this.delegate = delegate;
    }

    @Override
    public int compare(E o1, E o2) {
        return delegate.compare(o2, o1);
    }

    @Override
    public boolean predecessor(E o1, E o2) {
        return delegate.successor(o1, o2);
    }

    @Override
    public boolean successor(E o1, E o2) {
        return delegate.predecessor(o1, o2);
    }

    @Override
    public boolean isValid(E o1) {
        return delegate.isValid(o1);
    }

}

